const svg = $('#pn-svg'), slider = $('#pn-n'), out = $('#pn-nv');
// Enumerate partitions of n as arrays, parts in non-increasing order.
function partitionsOf(n){
  const res = [];
  function go(rem, max, cur){
    if(rem===0){ res.push(cur.slice()); return; }
    const lim = Math.min(rem, max);
    for(let k=lim; k>=1; k--){
      cur.push(k);
      go(rem-k, k, cur);
      cur.pop();
    }
  }
  go(n, n, []);
  return res;
}

function render(){
  svg.innerHTML = '';
  const n = parseInt(slider.value,10);
  const parts = partitionsOf(n);
  out.textContent = `n = ${n},  p(${n}) = ${parts.length}`;
  const W = 620, H = 320;
  const pad = 16;
  // Determine grid: we have parts.length partitions; want grid of columns × rows.
  // Each cell sized to fit the widest partition (largest part) × max rows.
  const maxPart = n; // widest any diagram gets
  const maxRows = n; // tallest any diagram gets
  const cellW = maxPart * 10 + 12; // +gutter
  const cellH = maxRows * 10 + 22;
  const cols = Math.max(1, Math.floor((W - 2*pad) / cellW));
  const rows = Math.ceil(parts.length / cols);
  const totalH = rows * cellH + 2*pad;
  // rescale vertically if too tall
  let scale = 1;
  if(totalH > H){ scale = (H - 2*pad) / (rows * cellH); }
  const box = Math.round(10*scale);
  for(let i=0;i<parts.length;i++){
    const col = i % cols;
    const row = Math.floor(i/cols);
    const cx = pad + col*cellW*scale;
    const cy = pad + row*cellH*scale;
    const p = parts[i];
    for(let r=0;r<p.length;r++){
      for(let c=0;c<p[r];c++){
        svg.appendChild(SVG('rect',{
          x: cx + c*box, y: cy + r*box,
          width: box-1, height: box-1,
          fill:'var(--cyan)', opacity: 0.85
        }));
      }
    }
    // label: part list
    const lbl = SVG('text',{
      x: cx, y: cy + p.length*box + 11,
      'font-size': Math.max(9, 10*scale), fill:'var(--mute)'
    });
    lbl.textContent = p.join('+');
    svg.appendChild(lbl);
  }
  // If rows exceed the box, add a hint
  if(scale < 1){
    const t = SVG('text',{x:W-pad, y:H-4, 'text-anchor':'end','font-size':11, fill:'var(--mute)'});
    t.textContent = `grid scaled ×${scale.toFixed(2)}`;
    svg.appendChild(t);
  }
}
slider.addEventListener('input', render);
render();

