const svg = $('#pent-svg'), Nin = $('#pent-N'), Nv = $('#pent-Nv'), out = $('#pent-out');

// Generate generalized pentagonal numbers and their signs
// Sequence: g_1=1 (k=1), g_{-1}=2 (k=-1), g_2=5 (k=2), g_{-2}=7, ...
// Sign = (-1)^{k+1} for k=1, -1 meaning same sign as k=1's group; actually:
// recurrence: p(n) = sum over k=1,2,... of (-1)^{k+1} [p(n-g_k) + p(n-g_{-k})]
// where g_k = k(3k-1)/2, g_{-k} = k(3k+1)/2.
function pentList(maxN){
  const out = [];
  for(let k=1; k*(3*k-1)/2 <= maxN; k++){
    const s = (k%2===1) ? +1 : -1;
    out.push([k*(3*k-1)/2, s]);
    if(k*(3*k+1)/2 <= maxN) out.push([k*(3*k+1)/2, s]);
  }
  return out;
}

function computeP(N){
  const P = new Array(N+1).fill(0);
  P[0] = 1;
  const pent = pentList(N);
  for(let n=1;n<=N;n++){
    let s = 0;
    for(const [g,sign] of pent){
      if(g>n) break;
      s += sign * P[n-g];
    }
    P[n] = s;
  }
  return { P, pent };
}

function render(){
  const N = parseInt(Nin.value,10);
  Nv.textContent = `N = ${N}`;
  const { P, pent } = computeP(N);
  svg.innerHTML = '';
  const W=620, H=240, pad={l:50,r:14,t:22,b:36};
  const maxV = Math.max(1, ...P);
  const scale = v => v>0 ? Math.log(1+v)/Math.log(1+maxV) : 0;
  const cw = (W-pad.l-pad.r)/(N+1);
  svg.appendChild(SVG('line',{x1:pad.l,y1:H-pad.b,x2:W-pad.r,y2:H-pad.b,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:pad.l,y1:pad.t,x2:pad.l,y2:H-pad.b,stroke:'var(--line)'}));
  for(let n=0;n<=N;n++){
    const v = P[n], x = pad.l + n*cw;
    const h = scale(v)*(H-pad.t-pad.b);
    if(h>0){
      svg.appendChild(SVG('rect',{x:x+1,y:H-pad.b-h,width:Math.max(1,cw-2),height:h,
        fill:'var(--green)',opacity:0.85}));
    }
    if(n%5===0){
      const t = SVG('text',{x:x+cw/2,y:H-pad.b+14,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
      t.textContent = n; svg.appendChild(t);
    }
  }
  const ax = SVG('text',{x:(W+pad.l-pad.r)/2, y:H-6, 'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  ax.textContent = 'n  (log bar height ∝ p(n))';
  svg.appendChild(ax);
  const tt = SVG('text',{x:W-pad.r, y:pad.t+4, 'text-anchor':'end','font-size':11, fill:'var(--blue)','font-style':'italic'});
  tt.textContent = `p(${N}) = ${P[N].toLocaleString()}`;
  svg.appendChild(tt);

  // readout: trace the recurrence for n=N
  const used = [];
  let acc = 0;
  for(const [g,sign] of pent){
    if(g>N) break;
    const contribution = sign * P[N-g];
    used.push(`  ${sign>0?'+':'-'} p(${N-g}) = ${sign>0?'+':'-'}${P[N-g]}`);
    acc += contribution;
  }
  const rows = [];
  rows.push(`p(${N}) via pentagonal recurrence:`);
  rows.push(used.join('\n'));
  rows.push(`  = ${acc} = p(${N})  ✓`);
  rows.push('');
  rows.push('pentagonal numbers used: ' + pent.map(([g,s])=> (s>0?'+':'-')+g).slice(0, Math.min(10,pent.length)).join(', ') + (pent.length>10?', …':''));
  out.textContent = rows.join('\n');
}
