const svg = $('#jtp-svg'), Nin = $('#jtp-N'), Nv = $('#jtp-Nv'), out = $('#jtp-out');
const D = 30;
function zeros(){ return new Array(D+1).fill(0); }
function mul(A,B){
  const C = zeros();
  for(let i=0;i<=D;i++){
    if(!A[i]) continue;
    for(let j=0;i+j<=D;j++){
      if(!B[j]) continue;
      C[i+j] += A[i]*B[j];
    }
  }
  return C;
}
function pentSum(N){
  const S = zeros();
  for(let k=-N;k<=N;k++){
    const g = k*(3*k-1)/2;
    if(g>=0 && g<=D) S[g] += (k%2===0)?1:-1;
  }
  return S;
}
function eulerProduct(N){
  let P = zeros(); P[0] = 1;
  for(let n=1;n<=N;n++){
    const q = zeros(); q[0] = 1;
    if(n<=D) q[n] = -1;
    P = mul(P, q);
  }
  return P;
}
function render(){
  const N = parseInt(Nin.value,10);
  Nv.textContent = `N = ${N}`;
  const S = pentSum(N), P = eulerProduct(N);
  svg.innerHTML = '';
