const N = 200;
const P = new Array(N+1).fill(0); P[0] = 1;
const pent = [];
for(let k=1; k*(3*k-1)/2 <= N; k++){
  const s = (k%2===1) ? +1 : -1;
  pent.push([k*(3*k-1)/2, s]);
  if(k*(3*k+1)/2 <= N) pent.push([k*(3*k+1)/2, s]);
}
for(let n=1;n<=N;n++){
  let s = 0;
  for(const [g,sign] of pent){
    if(g>n) break;
    s += sign * P[n-g];
  }
  P[n] = s;
}
function HR(n){
  if(n<=0) return 1;
  return Math.exp(Math.PI*Math.sqrt(2*n/3)) / (4*n*Math.sqrt(3));
}
